fn dot_product_ptx(record: &CatalogIntrinsic) -> &'static str {
    let dot = record.dot_product.as_ref().expect("dot-product record");
    match (dot.operation, dot.signedness, dot.adapter) {
        (
            DotProductOperation::Dp4a,
            DotProductSignedness::Signed,
            DotProductAdapter::DirectThreeOperands,
        ) => "dp4a.s32.s32 $0, $1, $2, $3;",
        (
            DotProductOperation::Dp4a,
            DotProductSignedness::Unsigned,
            DotProductAdapter::DirectThreeOperands,
        ) => "dp4a.u32.u32 $0, $1, $2, $3;",
        (
            DotProductOperation::Dp2a,
            DotProductSignedness::Signed,
            DotProductAdapter::InsertLowHalfFalse,
        ) => "dp2a.lo.s32.s32 $0, $1, $2, $3;",
        (
            DotProductOperation::Dp2a,
            DotProductSignedness::Unsigned,
            DotProductAdapter::InsertLowHalfFalse,
        ) => "dp2a.lo.u32.u32 $0, $1, $2, $3;",
        combination => panic!("unsupported generated dot-product recipe {combination:?}"),
    }
}

fn packed_alu_ptx_mnemonic(record: &CatalogIntrinsic) -> &'static str {
    let packed = record.packed_alu.as_ref().expect("packed-ALU record");
    match (packed.format, packed.operation, packed.adapter) {
        (PackedAluFormat::Bf16x2, PackedAluOperation::Add, PackedAluAdapter::DirectPackedU32) => {
            "add.rn.bf16x2"
        }
        (PackedAluFormat::Bf16x2, PackedAluOperation::Sub, PackedAluAdapter::DirectPackedU32) => {
            "sub.rn.bf16x2"
        }
        (PackedAluFormat::Bf16x2, PackedAluOperation::Mul, PackedAluAdapter::DirectPackedU32) => {
            "mul.rn.bf16x2"
        }
        (PackedAluFormat::Bf16x2, PackedAluOperation::Fma, PackedAluAdapter::DirectPackedU32) => {
            "fma.rn.bf16x2"
        }
        (
            PackedAluFormat::Bf16x2,
            PackedAluOperation::FmaRelu,
            PackedAluAdapter::DirectPackedU32,
        ) => "fma.rn.relu.bf16x2",
        (PackedAluFormat::Bf16x2, PackedAluOperation::Min, PackedAluAdapter::DirectPackedU32) => {
            "min.bf16x2"
        }
        (PackedAluFormat::Bf16x2, PackedAluOperation::Max, PackedAluAdapter::DirectPackedU32) => {
            "max.bf16x2"
        }
        (PackedAluFormat::Bf16x2, PackedAluOperation::Neg, PackedAluAdapter::DirectPackedU32) => {
            "neg.bf16x2"
        }
        (PackedAluFormat::Bf16x2, PackedAluOperation::Abs, PackedAluAdapter::DirectPackedU32) => {
            "abs.bf16x2"
        }
        (PackedAluFormat::F16x2, PackedAluOperation::Add, PackedAluAdapter::DirectPackedU32) => {
            "add.rn.f16x2"
        }
        (PackedAluFormat::F16x2, PackedAluOperation::Sub, PackedAluAdapter::DirectPackedU32) => {
            "sub.rn.f16x2"
        }
        (PackedAluFormat::F16x2, PackedAluOperation::Mul, PackedAluAdapter::DirectPackedU32) => {
            "mul.rn.f16x2"
        }
        (PackedAluFormat::F16x2, PackedAluOperation::Fma, PackedAluAdapter::DirectPackedU32) => {
            "fma.rn.f16x2"
        }
        (
            PackedAluFormat::F16x2,
            PackedAluOperation::FmaRelu,
            PackedAluAdapter::DirectPackedU32,
        ) => "fma.rn.relu.f16x2",
        (PackedAluFormat::F16x2, PackedAluOperation::Min, PackedAluAdapter::DirectPackedU32) => {
            "min.f16x2"
        }
        (PackedAluFormat::F16x2, PackedAluOperation::Max, PackedAluAdapter::DirectPackedU32) => {
            "max.f16x2"
        }
        (PackedAluFormat::F16x2, PackedAluOperation::Neg, PackedAluAdapter::DirectPackedU32) => {
            "neg.f16x2"
        }
        (PackedAluFormat::F16x2, PackedAluOperation::Abs, PackedAluAdapter::DirectPackedU32) => {
            "abs.f16x2"
        }
    }
}

fn packed_conversion_destination(record: &CatalogIntrinsic) -> &'static str {
    match record
        .packed_conversion
        .as_ref()
        .expect("packed-conversion record")
        .destination_format
    {
        PackedConversionDestinationFormat::Bf16x2 => "bf16x2",
        PackedConversionDestinationFormat::E4m3x2 => "e4m3x2",
        PackedConversionDestinationFormat::E5m2x2 => "e5m2x2",
        PackedConversionDestinationFormat::F16x2 => "f16x2",
    }
}

fn packed_conversion_element(record: &CatalogIntrinsic) -> &'static str {
    match record
        .packed_conversion
        .as_ref()
        .expect("packed-conversion record")
        .destination_format
    {
        PackedConversionDestinationFormat::Bf16x2 => "bf16",
        PackedConversionDestinationFormat::E4m3x2 => "e4m3",
        PackedConversionDestinationFormat::E5m2x2 => "e5m2",
        PackedConversionDestinationFormat::F16x2 => "f16",
    }
}

fn packed_conversion_result_width(record: &CatalogIntrinsic) -> u32 {
    match record
        .packed_conversion
        .as_ref()
        .expect("packed-conversion record")
        .destination_format
    {
        PackedConversionDestinationFormat::Bf16x2 | PackedConversionDestinationFormat::F16x2 => 32,
        PackedConversionDestinationFormat::E4m3x2 | PackedConversionDestinationFormat::E5m2x2 => 16,
    }
}

fn packed_conversion_rust_type(record: &CatalogIntrinsic) -> &'static str {
    match packed_conversion_result_width(record) {
        16 => "u16",
        32 => "u32",
        _ => unreachable!("closed packed-conversion result width"),
    }
}

fn packed_conversion_dialect_type(record: &CatalogIntrinsic) -> &'static str {
    match packed_conversion_result_width(record) {
        16 => "i16",
        32 => "i32",
        _ => unreachable!("closed packed-conversion result width"),
    }
}

fn packed_conversion_constraint(record: &CatalogIntrinsic) -> &'static str {
    match packed_conversion_result_width(record) {
        16 => "=h,f,f",
        32 => "=r,f,f",
        _ => unreachable!("closed packed-conversion result width"),
    }
}

fn packed_conversion_lowering_name(record: &CatalogIntrinsic) -> &'static str {
    match packed_conversion_result_width(record) {
        16 => "generated_packed_conversion_backend",
        32 => "generated_packed_conversion_inline_ptx",
        _ => unreachable!("closed packed-conversion result width"),
    }
}

fn packed_conversion_typed_llvm_name(record: &CatalogIntrinsic) -> Option<String> {
    let route = record
        .backend_lowerings
        .iter()
        .find(|lowering| lowering.backend == IntrinsicBackend::LlvmNvptx)
        .expect("packed conversion has an LLVM-NVPTX route");
    match route.mechanism {
        BackendLoweringMechanism::TypedNvvm => Some(record.llvm_identifier()),
        BackendLoweringMechanism::InlinePtx => None,
    }
}

fn packed_conversion_ptx_mnemonic(record: &CatalogIntrinsic) -> String {
    let conversion = record
        .packed_conversion
        .as_ref()
        .expect("packed-conversion record");
    debug_assert_eq!(
        conversion.source_format,
        PackedConversionSourceFormat::F32x2
    );
    debug_assert_eq!(
        conversion.adapter,
        PackedConversionAdapter::ReverseHighLowOperands
    );
    let rounding = match conversion.rounding {
        PackedConversionRounding::NearestEven => "rn",
        PackedConversionRounding::TowardZero => "rz",
    };
    let saturation = match conversion.saturation {
        PackedConversionSaturation::None => "",
        PackedConversionSaturation::Relu => ".relu",
        PackedConversionSaturation::Satfinite => ".satfinite",
        PackedConversionSaturation::SatfiniteRelu => ".satfinite.relu",
    };
    format!(
        "cvt.{rounding}{saturation}.{}.f32",
        packed_conversion_destination(record)
    )
}

fn llvm(record: &CatalogIntrinsic) -> &CatalogLlvm {
    record.llvm.as_ref().expect("LLVM-imported intrinsic")
}

fn source_label(record: &CatalogIntrinsic) -> String {
    match &record.source {
        IntrinsicSource::LlvmImported { source_record } => {
            format!("LLVM `{}` from `{source_record}`", llvm(record).symbol)
        }
        IntrinsicSource::PtxNative { instruction } => {
            format!("PTX-native `{instruction}`")
        }
    }
}

fn ldmatrix_attr_variants(
    record: &CatalogIntrinsic,
) -> (
    &'static str,
    &'static str,
    &'static str,
    &'static str,
    &'static str,
) {
    let variant = &record.ldmatrix.as_ref().expect("ldmatrix record").variant;
    let shape = match variant.shape {
        LdmatrixShape::M8n8 => "LdmatrixShapeAttr::M8n8",
        LdmatrixShape::M8n16 => "LdmatrixShapeAttr::M8n16",
        LdmatrixShape::M16n16 => "LdmatrixShapeAttr::M16n16",
    };
    let multiplicity = match variant.multiplicity {
        LdmatrixMultiplicity::X1 => "LdmatrixMultiplicityAttr::X1",
        LdmatrixMultiplicity::X2 => "LdmatrixMultiplicityAttr::X2",
        LdmatrixMultiplicity::X4 => "LdmatrixMultiplicityAttr::X4",
    };
    let layout = match variant.layout {
        LdmatrixLayout::Normal => "LdmatrixLayoutAttr::Normal",
        LdmatrixLayout::Transposed => "LdmatrixLayoutAttr::Transposed",
    };
    let element = match variant.element {
        LdmatrixElement::B16 => "LdmatrixElementAttr::B16",
        LdmatrixElement::B8 => "LdmatrixElementAttr::B8",
        LdmatrixElement::B8x16B4x16P64 => "LdmatrixElementAttr::B8x16B4x16P64",
        LdmatrixElement::B8x16B6x16P32 => "LdmatrixElementAttr::B8x16B6x16P32",
    };
    let state_space = match variant.state_space {
        LdmatrixStateSpace::Shared => "LdmatrixStateSpaceAttr::Shared",
    };
    (shape, multiplicity, layout, element, state_space)
}

fn register_mma_effective_kind(record: &CatalogIntrinsic) -> RegisterMmaKind {
    let mma = record.register_mma.as_ref().expect("register-MMA record");
    mma.kind.unwrap_or_else(|| {
        if record
            .llvm
            .as_ref()
            .is_some_and(|llvm| llvm.symbol.contains(".kind.f8f6f4."))
        {
            RegisterMmaKind::F8f6f4
        } else {
            RegisterMmaKind::Standard
        }
    })
}

fn register_mma_attr_variants(
    record: &CatalogIntrinsic,
) -> (
    &'static str,
    &'static str,
    &'static str,
    &'static str,
    &'static str,
    &'static str,
    &'static str,
    &'static str,
    &'static str,
) {
    let mma = record.register_mma.as_ref().expect("register-MMA record");
    let shape = match mma.shape {
        RegisterMmaShape::M8n8k4 => "RegisterMmaShapeAttr::M8n8k4",
        RegisterMmaShape::M8n8k16 => "RegisterMmaShapeAttr::M8n8k16",
        RegisterMmaShape::M8n8k32 => "RegisterMmaShapeAttr::M8n8k32",
        RegisterMmaShape::M8n8k128 => "RegisterMmaShapeAttr::M8n8k128",
        RegisterMmaShape::M16n8k4 => "RegisterMmaShapeAttr::M16n8k4",
        RegisterMmaShape::M16n8k8 => "RegisterMmaShapeAttr::M16n8k8",
        RegisterMmaShape::M16n8k16 => "RegisterMmaShapeAttr::M16n8k16",
        RegisterMmaShape::M16n8k32 => "RegisterMmaShapeAttr::M16n8k32",
        RegisterMmaShape::M16n8k64 => "RegisterMmaShapeAttr::M16n8k64",
        RegisterMmaShape::M16n8k128 => "RegisterMmaShapeAttr::M16n8k128",
        RegisterMmaShape::M16n8k256 => "RegisterMmaShapeAttr::M16n8k256",
    };
    let operation = match mma.operation {
        RegisterMmaOperation::Multiply => "RegisterMmaOperationAttr::Multiply",
        RegisterMmaOperation::AndPopc => "RegisterMmaOperationAttr::AndPopc",
        RegisterMmaOperation::XorPopc => "RegisterMmaOperationAttr::XorPopc",
    };
    let kind = match register_mma_effective_kind(record) {
        RegisterMmaKind::Standard => "RegisterMmaKindAttr::Standard",
        RegisterMmaKind::F8f6f4 => "RegisterMmaKindAttr::F8f6f4",
    };
    let accumulator = match mma.accumulator {
        RegisterMmaAccumulator::F16 => "RegisterMmaAccumulatorAttr::F16",
        RegisterMmaAccumulator::F32 => "RegisterMmaAccumulatorAttr::F32",
        RegisterMmaAccumulator::F64 => "RegisterMmaAccumulatorAttr::F64",
        RegisterMmaAccumulator::S32 => "RegisterMmaAccumulatorAttr::S32",
    };
    let element = |element| match element {
        RegisterMmaElement::Bf16 => "RegisterMmaElementAttr::Bf16",
        RegisterMmaElement::E2m1 => "RegisterMmaElementAttr::E2m1",
        RegisterMmaElement::E2m3 => "RegisterMmaElementAttr::E2m3",
        RegisterMmaElement::E3m2 => "RegisterMmaElementAttr::E3m2",
        RegisterMmaElement::E4m3 => "RegisterMmaElementAttr::E4m3",
        RegisterMmaElement::E5m2 => "RegisterMmaElementAttr::E5m2",
        RegisterMmaElement::F16 => "RegisterMmaElementAttr::F16",
        RegisterMmaElement::Tf32 => "RegisterMmaElementAttr::Tf32",
        RegisterMmaElement::F64 => "RegisterMmaElementAttr::F64",
        RegisterMmaElement::B1 => "RegisterMmaElementAttr::B1",
        RegisterMmaElement::S4 => "RegisterMmaElementAttr::S4",
        RegisterMmaElement::U4 => "RegisterMmaElementAttr::U4",
        RegisterMmaElement::S8 => "RegisterMmaElementAttr::S8",
        RegisterMmaElement::U8 => "RegisterMmaElementAttr::U8",
    };
    let layout = |layout| match layout {
        RegisterMmaLayout::Row => "RegisterMmaLayoutAttr::Row",
        RegisterMmaLayout::Col => "RegisterMmaLayoutAttr::Col",
    };
    let overflow = match mma.overflow {
        RegisterMmaOverflow::NotApplicable => "RegisterMmaOverflowAttr::NotApplicable",
        RegisterMmaOverflow::Wrapping => "RegisterMmaOverflowAttr::Wrapping",
        RegisterMmaOverflow::Satfinite => "RegisterMmaOverflowAttr::Satfinite",
    };
    (
        shape,
        operation,
        kind,
        accumulator,
        element(mma.a_element),
        element(mma.b_element),
        layout(mma.a_layout),
        layout(mma.b_layout),
        overflow,
    )
}

fn register_mma_fragment_counts(record: &CatalogIntrinsic) -> (usize, usize, usize, usize) {
    match record.register_mma.as_ref().unwrap().adapter {
        RegisterMmaAdapter::C2U32A2U32B1U32ToD2U32 => (2, 2, 1, 2),
        RegisterMmaAdapter::C2U32A4U32B2U32ToD2U32 => (2, 4, 2, 2),
        RegisterMmaAdapter::C4F32A2U32B1U32ToD4F32 => (4, 2, 1, 4),
        RegisterMmaAdapter::C4F32A4U32B2U32ToD4F32 | RegisterMmaAdapter::C4I32A4U32B2U32ToD4I32 => {
            (4, 4, 2, 4)
        }
        RegisterMmaAdapter::C2F64A1F64B1F64ToD2F64 | RegisterMmaAdapter::C2I32A1U32B1U32ToD2I32 => {
            (2, 1, 1, 2)
        }
        RegisterMmaAdapter::C4I32A2U32B1U32ToD4I32 => (4, 2, 1, 4),
    }
}

fn expected_ptx_head(record: &CatalogIntrinsic) -> String {
    let mut head = record.expected_ptx.mnemonic.clone();
    for modifier in &record.expected_ptx.modifiers {
        write!(head, ".{modifier}").unwrap();
    }
    head
}

fn register_list(first: usize, count: usize) -> String {
    format!(
        "{{{}}}",
        (first..first + count)
            .map(|index| format!("${index}"))
            .collect::<Vec<_>>()
            .join(", ")
    )
}

fn register_mma_template(record: &CatalogIntrinsic) -> String {
    let (c_count, a_count, b_count, d_count) = register_mma_fragment_counts(record);
    let d = register_list(0, d_count);
    let c = register_list(d_count, c_count);
    let a = register_list(d_count + c_count, a_count);
    let b = register_list(d_count + c_count + a_count, b_count);
    format!("{} {d}, {a}, {b}, {c};", expected_ptx_head(record))
}

fn register_mma_constraints(record: &CatalogIntrinsic) -> String {
    let mma = record.register_mma.as_ref().unwrap();
    let (c_count, a_count, b_count, d_count) = register_mma_fragment_counts(record);
    let (output, c, packed) =
        match mma.adapter {
            RegisterMmaAdapter::C2U32A2U32B1U32ToD2U32
            | RegisterMmaAdapter::C2U32A4U32B2U32ToD2U32 => ("=r", "r", "r"),
            RegisterMmaAdapter::C4F32A2U32B1U32ToD4F32
            | RegisterMmaAdapter::C4F32A4U32B2U32ToD4F32 => ("=f", "f", "r"),
            RegisterMmaAdapter::C2F64A1F64B1F64ToD2F64 => ("=d", "d", "d"),
            RegisterMmaAdapter::C2I32A1U32B1U32ToD2I32
            | RegisterMmaAdapter::C4I32A4U32B2U32ToD4I32
            | RegisterMmaAdapter::C4I32A2U32B1U32ToD4I32 => ("=r", "r", "r"),
        };
    std::iter::repeat_n(output, d_count)
        .chain(std::iter::repeat_n(c, c_count))
        .chain(std::iter::repeat_n(packed, a_count + b_count))
        .collect::<Vec<_>>()
        .join(",")
}

fn register_mma_result_variant(record: &CatalogIntrinsic) -> &'static str {
    match record.register_mma.as_ref().unwrap().adapter {
        RegisterMmaAdapter::C2U32A2U32B1U32ToD2U32 | RegisterMmaAdapter::C2U32A4U32B2U32ToD2U32 => {
            "GeneratedMmaResultType::I32"
        }
        RegisterMmaAdapter::C4F32A2U32B1U32ToD4F32 | RegisterMmaAdapter::C4F32A4U32B2U32ToD4F32 => {
            "GeneratedMmaResultType::F32"
        }
        RegisterMmaAdapter::C2F64A1F64B1F64ToD2F64 => "GeneratedMmaResultType::F64",
        RegisterMmaAdapter::C2I32A1U32B1U32ToD2I32
        | RegisterMmaAdapter::C4I32A4U32B2U32ToD4I32
        | RegisterMmaAdapter::C4I32A2U32B1U32ToD4I32 => "GeneratedMmaResultType::I32",
    }
}

fn sparse_mma_fragment_counts(record: &CatalogIntrinsic) -> (usize, usize, usize, usize) {
    match record.sparse_mma.as_ref().unwrap().adapter {
        SparseMmaAdapter::C2U32A4U32B4U32MetadataU32SelectorU32ToD2U32 => (2, 4, 4, 2),
        SparseMmaAdapter::C4F32A4U32B4U32MetadataU32SelectorU32ToD4F32
        | SparseMmaAdapter::C4I32A4U32B4U32MetadataU32SelectorU32ToD4I32 => (4, 4, 4, 4),
        SparseMmaAdapter::C4I32A2U32B2U32MetadataU32SelectorU32ToD4I32 => (4, 2, 2, 4),
    }
}

fn sparse_mma_selector_values(record: &CatalogIntrinsic) -> &'static [u32] {
    match record.sparse_mma.as_ref().unwrap().selector {
        SparseMmaSelector::ImmediateZeroOrOne => &[0, 1],
        SparseMmaSelector::ImmediateZero => &[0],
    }
}

fn sparse_mma_selector_description(record: &CatalogIntrinsic) -> &'static str {
    match record.sparse_mma.as_ref().unwrap().selector {
        SparseMmaSelector::ImmediateZeroOrOne => "the compile-time constant `0` or `1`",
        SparseMmaSelector::ImmediateZero => "the compile-time constant `0`",
    }
}

fn sparse_mma_selector_error(record: &CatalogIntrinsic) -> &'static str {
    match record.sparse_mma.as_ref().unwrap().selector {
        SparseMmaSelector::ImmediateZeroOrOne => {
            "sparse MMA selector must be the compile-time constant 0 or 1"
        }
        SparseMmaSelector::ImmediateZero => {
            "sparse MMA selector must be the compile-time constant 0"
        }
    }
}

const SPARSE_MMA_STANDARD_METADATA_RULE: &str = "Every 4-bit metadata group must encode two distinct 2-bit indices; `0x0`, `0x5`, `0xa`, and `0xf` are undefined behavior.";
const SPARSE_MMA_ORDERED_METADATA_RULE: &str = "Every 4-bit metadata group must be `0x4`, `0x8`, `0x9`, `0xc`, `0xd`, or `0xe`; any other value is undefined behavior.";

fn sparse_mma_metadata_rule(mma: &SparseMma) -> &'static str {
    match mma.metadata {
        SparseMmaMetadata::Standard => SPARSE_MMA_STANDARD_METADATA_RULE,
        SparseMmaMetadata::Ordered => SPARSE_MMA_ORDERED_METADATA_RULE,
    }
}

fn sparse_mma_import_adapter(record: &CatalogIntrinsic) -> &'static str {
    match record.sparse_mma.as_ref().unwrap().adapter {
        SparseMmaAdapter::C2U32A4U32B4U32MetadataU32SelectorU32ToD2U32 => {
            "GeneratedMmaImportAdapter::C2U32A4U32B4U32ToD2U32"
        }
        SparseMmaAdapter::C4F32A4U32B4U32MetadataU32SelectorU32ToD4F32 => {
            "GeneratedMmaImportAdapter::C4F32A4U32B4U32ToD4F32"
        }
        SparseMmaAdapter::C4I32A2U32B2U32MetadataU32SelectorU32ToD4I32 => {
            "GeneratedMmaImportAdapter::C4I32A2U32B2U32ToD4I32"
        }
        SparseMmaAdapter::C4I32A4U32B4U32MetadataU32SelectorU32ToD4I32 => {
            "GeneratedMmaImportAdapter::C4I32A4U32B4U32ToD4I32"
        }
    }
}

fn sparse_mma_attr_variants(
    record: &CatalogIntrinsic,
) -> (
    &'static str,
    &'static str,
    &'static str,
    &'static str,
    &'static str,
    &'static str,
    &'static str,
    &'static str,
    &'static str,
) {
    let mma = record.sparse_mma.as_ref().expect("sparse-MMA record");
    let shape = match mma.shape {
        SparseMmaShape::M16n8k32 => "SparseMmaShapeAttr::M16n8k32",
        SparseMmaShape::M16n8k64 => "SparseMmaShapeAttr::M16n8k64",
        SparseMmaShape::M16n8k128 => "SparseMmaShapeAttr::M16n8k128",
    };
    let accumulator = match mma.accumulator {
        SparseMmaAccumulator::F16 => "SparseMmaAccumulatorAttr::F16",
        SparseMmaAccumulator::F32 => "SparseMmaAccumulatorAttr::F32",
        SparseMmaAccumulator::S32 => "SparseMmaAccumulatorAttr::S32",
    };
    let element = |element| match element {
        SparseMmaElement::E2m1 => "SparseMmaElementAttr::E2m1",
        SparseMmaElement::E2m3 => "SparseMmaElementAttr::E2m3",
        SparseMmaElement::E3m2 => "SparseMmaElementAttr::E3m2",
        SparseMmaElement::E4m3 => "SparseMmaElementAttr::E4m3",
        SparseMmaElement::E5m2 => "SparseMmaElementAttr::E5m2",
        SparseMmaElement::S4 => "SparseMmaElementAttr::S4",
        SparseMmaElement::U4 => "SparseMmaElementAttr::U4",
        SparseMmaElement::S8 => "SparseMmaElementAttr::S8",
        SparseMmaElement::U8 => "SparseMmaElementAttr::U8",
    };
    let layout = |layout| match layout {
        SparseMmaLayout::Row => "SparseMmaLayoutAttr::Row",
        SparseMmaLayout::Col => "SparseMmaLayoutAttr::Col",
    };
    let overflow = match mma.overflow {
        SparseMmaOverflow::NotApplicable => "SparseMmaOverflowAttr::NotApplicable",
        SparseMmaOverflow::Wrapping => "SparseMmaOverflowAttr::Wrapping",
        SparseMmaOverflow::Satfinite => "SparseMmaOverflowAttr::Satfinite",
    };
    let metadata = match mma.metadata {
        SparseMmaMetadata::Standard => "SparseMmaMetadataAttr::Standard",
        SparseMmaMetadata::Ordered => "SparseMmaMetadataAttr::Ordered",
    };
    let selector = match mma.selector {
        SparseMmaSelector::ImmediateZeroOrOne => "SparseMmaSelectorAttr::ImmediateZeroOrOne",
        SparseMmaSelector::ImmediateZero => "SparseMmaSelectorAttr::ImmediateZero",
    };
    (
        shape,
        accumulator,
        element(mma.a_element),
        element(mma.b_element),
        layout(mma.a_layout),
        layout(mma.b_layout),
        overflow,
        metadata,
        selector,
    )
}

fn sparse_mma_ptx_head(record: &CatalogIntrinsic) -> String {
    let mut head = record.expected_ptx.mnemonic.clone();
    for modifier in &record.expected_ptx.modifiers {
        write!(head, ".{modifier}").unwrap();
    }
    head
}

fn sparse_mma_template(record: &CatalogIntrinsic) -> String {
    let (c_count, a_count, b_count, d_count) = sparse_mma_fragment_counts(record);
    let d = register_list(0, d_count);
    let c = register_list(d_count, c_count);
    let a = register_list(d_count + c_count, a_count);
    let b = register_list(d_count + c_count + a_count, b_count);
    let metadata = d_count + c_count + a_count + b_count;
    let selector = metadata + 1;
    format!(
        "{} {d}, {a}, {b}, {c}, ${metadata}, ${selector};",
        sparse_mma_ptx_head(record)
    )
}

fn sparse_mma_constraints(record: &CatalogIntrinsic) -> String {
    let mma = record.sparse_mma.as_ref().unwrap();
    let (c_count, a_count, b_count, d_count) = sparse_mma_fragment_counts(record);
    let (output, accumulator) = match mma.accumulator {
        SparseMmaAccumulator::F16 => ("=r", "r"),
        SparseMmaAccumulator::F32 => ("=f", "f"),
        SparseMmaAccumulator::S32 => ("=r", "r"),
    };
    std::iter::repeat_n(output, d_count)
        .chain(std::iter::repeat_n(accumulator, c_count))
        .chain(std::iter::repeat_n("r", a_count + b_count + 1))
        .chain(std::iter::once("n"))
        .collect::<Vec<_>>()
        .join(",")
}

fn sparse_mma_result_variant(record: &CatalogIntrinsic) -> &'static str {
    match record.sparse_mma.as_ref().unwrap().accumulator {
        SparseMmaAccumulator::F16 => "GeneratedMmaResultType::I32",
        SparseMmaAccumulator::F32 => "GeneratedMmaResultType::F32",
        SparseMmaAccumulator::S32 => "GeneratedMmaResultType::I32",
    }
}

fn sparse_mma_carriers(record: &CatalogIntrinsic) -> (String, String) {
    let mma = record.sparse_mma.as_ref().unwrap();
    let (c_count, a_count, b_count, d_count) = sparse_mma_fragment_counts(record);
    let accumulator = match mma.accumulator {
        SparseMmaAccumulator::F16 => "MmaCarrier::U32",
        SparseMmaAccumulator::F32 => "MmaCarrier::F32",
        SparseMmaAccumulator::S32 => "MmaCarrier::I32",
    };
    let carrier_slice = |carriers: Vec<&str>| format!("&[{}]", carriers.join(", "));
    let operands = carrier_slice(
        std::iter::repeat_n(accumulator, c_count)
            .chain(std::iter::repeat_n(
                "MmaCarrier::U32",
                a_count + b_count + 2,
            ))
            .collect(),
    );
    let results = carrier_slice(std::iter::repeat_n(accumulator, d_count).collect());
    (operands, results)
}

fn intrinsic_marker(catalog: &CatalogFile, record: &CatalogIntrinsic) -> String {
    format!("v{}:{}", catalog.intrinsic_abi, record.rust.abi_id)
}

fn hardware_target_label(target: &CatalogHardwareTarget) -> String {
    match target {
        CatalogHardwareTarget::All => "all".to_owned(),
        CatalogHardwareTarget::AnyOf { alternatives } => alternatives
            .iter()
            .map(hardware_alternative_label)
            .collect::<Vec<_>>()
            .join(" or "),
        CatalogHardwareTarget::TargetMatrix { contracts } => contracts
            .iter()
            .map(|contract| {
                let selectors = contract
                    .selectors
                    .iter()
                    .map(|selector| format!("{}={}", selector.name, selector.value))
                    .collect::<Vec<_>>()
                    .join(", ");
                let alternatives = contract
                    .alternatives
                    .iter()
                    .map(|alternative| {
                        format!(
                            "{} at PTX {}",
                            hardware_alternative_label(&alternative.hardware),
                            alternative.minimum_ptx
                        )
                    })
                    .collect::<Vec<_>>()
                    .join(" or ");
                if selectors.is_empty() {
                    alternatives
                } else {
                    format!("{alternatives} for {selectors}")
                }
            })
            .collect::<Vec<_>>()
            .join("; "),
    }
}

fn hardware_alternative_label(alternative: &CatalogHardwareAlternative) -> String {
    match alternative {
        CatalogHardwareAlternative::MinimumSm { sm } => format!("sm_{sm}+"),
        CatalogHardwareAlternative::ExactArchitecture { sm } => format!("sm_{sm}a"),
        CatalogHardwareAlternative::FamilyTarget { sm } => format!("sm_{sm}f"),
    }
}

fn generated_hardware_target(target: &CatalogHardwareTarget) -> String {
    match target {
        CatalogHardwareTarget::All => "GeneratedHardwareTarget::All".to_owned(),
        CatalogHardwareTarget::AnyOf { alternatives } => {
            let alternatives = alternatives
                .iter()
                .map(generated_hardware_alternative)
                .collect::<Vec<_>>()
                .join(", ");
            format!("GeneratedHardwareTarget::AnyOf(&[{alternatives}])")
        }
        CatalogHardwareTarget::TargetMatrix { contracts } => {
            let contracts = contracts
                .iter()
                .map(generated_target_contract)
                .collect::<Vec<_>>()
                .join(", ");
            format!("GeneratedHardwareTarget::TargetMatrix {{ contracts: &[{contracts}] }}")
        }
    }
}

fn generated_target_contract(contract: &CatalogTargetContract) -> String {
    let selectors = contract
        .selectors
        .iter()
        .map(|selector| {
            format!(
                "GeneratedTargetSelectorBinding {{ name: {:?}, value: {:?} }}",
                selector.name, selector.value
            )
        })
        .collect::<Vec<_>>()
        .join(", ");
    let alternatives = contract
        .alternatives
        .iter()
        .map(|alternative| {
            format!(
                "GeneratedTargetAlternative {{ minimum_ptx: GeneratedPtxVersion::from_encoded({}), hardware: {} }}",
                alternative.minimum_ptx.encoded(),
                generated_hardware_alternative(&alternative.hardware)
            )
        })
        .collect::<Vec<_>>()
        .join(", ");
    format!(
        "GeneratedTargetContract {{ selectors: &[{selectors}], alternatives: &[{alternatives}] }}"
    )
}

fn generated_hardware_alternative(alternative: &CatalogHardwareAlternative) -> String {
    match alternative {
        CatalogHardwareAlternative::MinimumSm { sm } => {
            format!("GeneratedHardwareAlternative::MinimumSm({sm})")
        }
        CatalogHardwareAlternative::ExactArchitecture { sm } => {
            format!("GeneratedHardwareAlternative::ExactArchitecture({sm})")
        }
        CatalogHardwareAlternative::FamilyTarget { sm } => {
            format!("GeneratedHardwareAlternative::FamilyTarget({sm})")
        }
    }
}

fn backend_label(backend: IntrinsicBackend) -> &'static str {
    match backend {
        IntrinsicBackend::LlvmNvptx => "llvm_nvptx",
        IntrinsicBackend::LibNvvm => "lib_nvvm",
    }
}

fn lowering_mechanism_label(mechanism: BackendLoweringMechanism) -> &'static str {
    match mechanism {
        BackendLoweringMechanism::TypedNvvm => "typed_nvvm",
        BackendLoweringMechanism::InlinePtx => "inline_ptx",
    }
}

fn evidence_stage_label(stage: EvidenceStageKind) -> &'static str {
    match stage {
        EvidenceStageKind::DeclarationCanonicalization => "declaration canonicalization",
        EvidenceStageKind::BackendCodegen => "backend codegen",
        EvidenceStageKind::DeviceLink => "device link",
        EvidenceStageKind::PtxAssembly => "PTX assembly",
        EvidenceStageKind::Runtime => "runtime",
    }
}

fn render_raw_mod(catalog: &CatalogFile, hash: &str) -> String {
    let mut output = rust_header(catalog, hash);
    let abi_module = format!("__cuda_oxide_intrinsic_abi_v{}", catalog.intrinsic_abi);
    writeln!(
        output,
        "#[doc(hidden)]\n#[path = \"abi_v{}.rs\"]\npub mod {abi_module};\n",
        catalog.intrinsic_abi
    )
    .unwrap();
    for module in modules(catalog) {
        writeln!(
            output,
            "/// Generated `{module}` intrinsic source API.\npub mod {module} {{"
        )
        .unwrap();
        for record in catalog
            .intrinsics
            .iter()
            .filter(|record| record.rust.module == module)
        {
            writeln!(
                output,
                "    pub use crate::{abi_module}::{} as {};",
                record.rust.abi_id, record.rust.name
            )
            .unwrap();
        }
        output.push_str("}\n\n");
    }
    output.push_str("#[cfg(test)]\n#[allow(clippy::type_complexity)]\nmod tests {\n");
    for record in &catalog.intrinsics {
        let arguments = record.rust.arguments.join(", ");
        writeln!(
            output,
            "    #[test]\n    fn public_{}_reexports_abi_{}() {{",
            record.rust.name, record.rust.abi_id
        )
        .unwrap();
        writeln!(
            output,
            "        let public: {}fn({}) -> {} = super::{}::{};",
            if record.rust.safe { "" } else { "unsafe " },
            arguments,
            record.rust.result,
            record.rust.module,
            record.rust.name
        )
        .unwrap();
        writeln!(
            output,
            "        let canonical: {}fn({}) -> {} = super::{abi_module}::{};",
            if record.rust.safe { "" } else { "unsafe " },
            arguments,
            record.rust.result,
            record.rust.abi_id
        )
        .unwrap();
        output.push_str("        assert_eq!(public as usize, canonical as usize);\n    }\n");
    }
    output.push_str("}\n");
    output
}

fn render_raw_abi(catalog: &CatalogFile, hash: &str) -> String {
    let mut output = rust_header(catalog, hash);
    output.push_str("//! Raw ABI functions recognized by cuda-oxide.\n\n");
    for record in &catalog.intrinsics {
        writeln!(output, "/// {}", record.summary).unwrap();
        writeln!(output, "///").unwrap();
        writeln!(
            output,
            "/// Catalog ID: `{}`. Source: {}; expects PTX `{}`.",
            record.id,
            source_label(record),
            record.expected_ptx
        )
        .unwrap();
        if is_blackwell_ldmatrix(record) {
            writeln!(
                output,
                "/// Available on `{}` targets. Instruction floor PTX {}; the selected target may require a newer PTX version.",
                hardware_target_label(&record.target.hardware),
                record.target.minimum_ptx
            )
            .unwrap();
        } else {
            writeln!(
                output,
                "/// Available on `{}` targets from PTX {}.",
                hardware_target_label(&record.target.hardware),
                record.target.minimum_ptx
            )
            .unwrap();
        }
        if let Some(operation) = record.tcgen05.as_ref().map(|tcgen05| tcgen05.operation)
            && let Some(participation) = tcgen05_participation_doc(operation)
        {
            writeln!(output, "/// {participation}").unwrap();
        }
        if record.tcgen05.is_some() {
            output.push_str(
                "/// All tcgen05 operations in the kernel must use the same CTA-group mode.\n",
            );
        }
        if let Some(reason) = &record.rust.safe_allowlist_reason {
            writeln!(output, "/// Safe because {reason}").unwrap();
        }
        if !record.rust.safe {
            output.push_str("///\n/// # Safety\n");
            if let Some(ldmatrix) = &record.ldmatrix {
                let variant = &ldmatrix.variant;
                let contributing_lanes = variant.multiplicity.register_count() * 8;
                let readable_bytes = if variant.shape == LdmatrixShape::M16n16 {
                    32
                } else {
                    16
                };
                let participation = match ldmatrix.safety.participation {
                    LdmatrixParticipation::AllWarpLanesSameInstruction => {
                        "All 32 warp lanes must execute the same instruction."
                    }
                    LdmatrixParticipation::AllWarpLanesSameInstructionAndQualifiersNoExitedLanes => {
                        "All 32 warp lanes must execute the same instruction and qualifiers; no lane may have exited."
                    }
                };
                writeln!(
                    output,
                    "/// {participation} PTX maps {contributing_lanes} lane-provided row addresses for this {:?} variant; addresses may alias, but each used address must be 16-byte aligned and have {readable_bytes} readable shared-memory bytes.",
                    variant.multiplicity
                )
                .unwrap();
                if matches!(
                    ldmatrix.safety.address_contract,
                    crate::model::LdmatrixAddressContract::WarpLaneAddressesMappedByMultiplicitySixteenByteAlignedSixteenBytesReadableWithSm75Replication
                ) && contributing_lanes < 32
                {
                    output.push_str("/// For portable sm_75 behavior, otherwise-unused lanes must also carry valid addresses replicated from the contributing lanes.\n");
                }
                output.push_str(
                    "/// This weak memory operation does not replace a required barrier or fence.\n",
                );
            } else if let Some((multiplicity, _)) = stmatrix_variant(record) {
                let address_lanes = multiplicity.register_count() * 8;
                writeln!(
                    output,
                    "/// All 32 warp lanes must execute the same instruction. The first {address_lanes} lanes must provide valid, 16-byte-aligned shared-memory row addresses."
                )
                .unwrap();
                output.push_str(
                    "/// Register operands must contain the packed b16 fragments required by the selected layout.\n/// This weak memory operation does not replace a required barrier or fence.\n",
                );
            } else if let Some(mma) = &record.sparse_mma {
                let (c_count, a_count, b_count, _) = sparse_mma_fragment_counts(record);
                output.push_str(
                    "/// All 32 warp lanes must execute the same sparse MMA instruction with the same qualifiers, and no lane may have exited.\n",
                );
                writeln!(
                    output,
                    "/// `_arg0`, `_arg1`, and `_arg2` hold this lane's {c_count}-register C, {a_count}-register A, and {b_count}-register B fragments; `_arg3` holds its sparse metadata."
                )
                .unwrap();
                writeln!(
                    output,
                    "/// `_arg4` must be {}.",
                    sparse_mma_selector_description(record)
                )
                .unwrap();
                output.push_str("/// The operation is register-only and is not a memory fence.\n");
                writeln!(output, "/// {}", sparse_mma_metadata_rule(mma)).unwrap();
                writeln!(
                    output,
                    "/// See the [PTX sparse MMA fragment layouts]({}).",
                    record.target.ptx_isa_url
                )
                .unwrap();
                match mma.overflow {
                    SparseMmaOverflow::NotApplicable => {}
                    SparseMmaOverflow::Wrapping => {
                        output.push_str(
                            "/// Signed accumulator overflow wraps because this form omits `.satfinite`.\n",
                        );
                    }
                    SparseMmaOverflow::Satfinite => output.push_str(
                        "/// Signed accumulator overflow clamps to the finite `i32` range.\n",
                    ),
                }
            } else if let Some(mma) = &record.register_mma {
                output.push_str(
                    "/// All 32 warp lanes must execute the same `mma.sync.aligned` instruction with the same qualifiers, and no lane may have exited.\n\
                     /// `_arg0`, `_arg1`, and `_arg2` must contain this lane's C, A, and B fragments in the documented PTX layout.\n\
                     /// The operation is register-only and is not a memory fence.\n",
                );
                writeln!(
                    output,
                    "/// See the [PTX MMA fragment layouts]({}).",
                    record.target.ptx_isa_url
                )
                .unwrap();
                if mma.overflow == RegisterMmaOverflow::Wrapping {
                    output.push_str("/// Signed accumulator overflow wraps because this form omits `.satfinite`.\n");
                } else if mma.overflow == RegisterMmaOverflow::Satfinite {
                    output.push_str(
                        "/// Signed accumulator overflow clamps to the finite `i32` range.\n",
                    );
                }
            } else if record.movmatrix.is_some() {
                output.push_str(
                    "/// All 32 warp lanes must execute the same instruction, and no lane may have exited.\n\
                     /// `_arg0` must contain this lane's two packed b16 input elements.\n\
                     /// The operation is register-only and is not a memory fence.\n",
                );
            } else if record.redux.is_some() {
                output.push_str(
                    "/// The executing lane must be named in `mask`. Every non-exited lane named in `mask` must execute the same `redux.sync` operation with the same qualifiers and mask.\n\
                     /// The instruction waits for those lanes; violating this participation contract makes the PTX operation undefined.\n",
                );
            } else if record.warp_barrier.is_some() {
                output.push_str(
                    "/// The executing lane must be named in `mask`. Every non-exited lane named in `mask` must execute the same `bar.warp.sync` operation with the same mask.\n\
                     /// On `sm_6x` and earlier, all lanes named in `mask` must execute the barrier in convergence, and no lane outside `mask` may be active when it executes.\n\
                     /// The barrier orders memory accesses among participating lanes; violating the participation contract makes the PTX operation undefined.\n",
                );
            } else if record.warp_shuffle.is_some() {
                output.push_str(
                    "/// The executing lane must be named in `mask`. Every non-exited lane named in `mask` must execute the same `shfl.sync` operation with the same qualifiers and mask.\n\
                     /// On `sm_6x` and earlier, all lanes named in `mask` must execute in convergence, and no lane outside `mask` may be active.\n\
                     /// If the computed source lane is in range, it must be active and named in `mask`; otherwise the result is undefined. If PTX marks the computed source out of range, the calling lane's input is copied.\n",
                );
                if record
                    .warp_shuffle
                    .as_ref()
                    .is_some_and(|shuffle| shuffle.value_kind == WarpShuffleValueKind::I64)
                {
                    output.push_str(
                        "/// The 64-bit value is moved by two `b32` shuffles in one convergent block.\n",
                    );
                }
            } else if record.warp_match.is_some() {
                output.push_str(
                    "/// The executing lane must be named in `mask`. Every non-exited lane named in `mask` must execute the same `match.sync` operation with the same qualifiers and mask.\n\
                     /// Violating this participation contract makes the PTX operation undefined.\n",
                );
            } else if record.family == "elect" {
                output.push_str(
                    "/// The executing lane must be named in `mask`. Every non-exited lane named in `mask` must execute the same `elect.sync` operation with the same mask.\n\
                     /// Violating this participation contract makes the PTX operation undefined.\n",
                );
            } else if record.vote.is_some() {
                output.push_str(
                    "/// The executing lane must be named in `mask`. Every non-exited lane named in `mask` must execute the same `vote.sync` operation with the same qualifiers and mask.\n\
                     /// On `sm_6x` and earlier, all lanes named in `mask` must execute in convergence, and no lane outside `mask` may be active.\n\
                     /// Violating this participation contract makes the PTX operation undefined.\n",
                );
            } else if record.family == "sync" {
                output.push_str(
                    "/// Every active thread in the CTA must reach the same barrier. Calling it from divergent control flow can deadlock the CTA.\n",
                );
            } else if record.family == "cluster_barrier" {
                let barrier = record
                    .cluster_barrier
                    .as_ref()
                    .expect("cluster-barrier contract");
                output.push_str(
                    "/// Each non-exited cluster thread must arrive exactly once before the barrier completes, then execute the matching wait.\n",
                );
                if barrier.aligned {
                    output.push_str(
                        "/// Every non-exited thread in the warp must execute this aligned instruction with identical control flow.\n",
                    );
                }
                if barrier.ordering == ClusterBarrierOrdering::Relaxed {
                    output.push_str(
                        "/// This relaxed arrival does not publish earlier memory accesses; add the required cluster-scope fence before it.\n",
                    );
                }
            } else if let Some(cluster) = &record.cluster_memory {
                match cluster.operation {
                    ClusterMemoryOperation::MapSharedRank => output.push_str(
                        "/// `_arg0` must point into CTA shared memory, and `_arg1` must name a rank in the same live cluster.\n\
                         /// The result is a cluster shared-address carrier; an ordinary pointer dereference is not a remote shared-memory access.\n",
                    ),
                    ClusterMemoryOperation::ReadU32 => output.push_str(
                        "/// `_arg0` must point to an aligned readable `u32` in CTA shared memory, and `_arg1` must name a rank in the same live cluster.\n\
                         /// The target CTA must publish the value with the required cluster synchronization before this weak load.\n",
                    ),
                }
            } else if let Some(control) = &record.wgmma_control {
                output.push_str(
                    "/// All four warps in the warpgroup must execute this instruction in convergence with the same control flow.\n",
                );
                match control.mode {
                    WgmmaControlMode::Fence => output.push_str(
                        "/// Issue it after register writes and before the WGMMA operations that consume those registers.\n",
                    ),
                    WgmmaControlMode::CommitGroup => output.push_str(
                        "/// Issue it only after the warpgroup has submitted the WGMMA operations to commit.\n",
                    ),
                    WgmmaControlMode::WaitGroup => output.push_str(
                        "/// `_arg0` must be a compile-time constant shared by the whole warpgroup.\n",
                    ),
                }
            } else if let Some(tma) = &record.tma {
                match tma.adapter {
                    TmaAdapter::G2sPointersCoordinatesBarrierInjectDefaults
                    | TmaAdapter::G2sPointersCoordinatesBarrierMaskInjectDefaults => output
                        .push_str(
                            "/// The destination and barrier must be valid shared-memory objects, and the tensor map must be a live descriptor for this dimensionality.\n\
                             /// Keep every object alive until the asynchronous copy completes. Only the designated issuing thread may start this transfer.\n",
                        ),
                    TmaAdapter::S2gPointersCoordinatesInjectDefaults => output.push_str(
                        "/// The source must name a live shared-memory tile, and the tensor map must be a live descriptor for this dimensionality.\n\
                         /// Keep both objects alive until the committed bulk-copy group completes.\n",
                    ),
                    TmaAdapter::NoOperands | TmaAdapter::CompileTimeConstantMaxPending => {}
                }
            } else if let Some(bridge) = &record.cp_async_mbarrier {
                output.push_str(
                    "/// `_arg0` must point to a live, initialized, eight-byte-aligned mbarrier object in shared memory.\n\
                     /// The issuing thread must have prior `cp.async` operations, and the object must remain valid until they complete.\n",
                );
                match bridge.operation {
                    CpAsyncMbarrierOperation::Arrive => output.push_str(
                        "/// This instruction increments the pending count before scheduling the asynchronous arrival; that increment must not exceed the barrier's pending-count limit.\n",
                    ),
                    CpAsyncMbarrierOperation::ArriveNoInc => output.push_str(
                        "/// The barrier's initial pending count must already include the asynchronous arrival because this form does not increment it.\n",
                    ),
                }
            } else if let Some(mbarrier) = &record.mbarrier_basic {
                output.push_str(
                    "/// `_arg0` must point to a live, eight-byte-aligned mbarrier object in shared memory.\n",
                );
                match mbarrier.operation {
                    MbarrierBasicOperation::Init => output.push_str(
                        "/// Exactly one thread may initialize the object. `_arg1` must be in `1..=0xFFFFF` and include every arrival in the phase.\n\
                         /// The object must be uninitialized or invalidated, with no concurrent barrier operation.\n",
                    ),
                    MbarrierBasicOperation::Arrive => output.push_str(
                        "/// The object must be initialized, and this arrival must be included in the current phase's expected count.\n\
                         /// Use the returned token only with the same object and phase.\n",
                    ),
                    MbarrierBasicOperation::TestWait => output.push_str(
                        "/// The object must be initialized. `_arg1` must be a token returned for the same object and phase.\n",
                    ),
                    MbarrierBasicOperation::Inval => output.push_str(
                        "/// The object must be initialized and no thread or asynchronous operation may still use it.\n\
                         /// Exactly one thread may invalidate the object.\n",
                    ),
                }
            } else if let Some(mbarrier) = &record.mbarrier_extended {
                output.push_str(
                    "/// This is a convergent, side-effecting operation with a compiler memory clobber.\n",
                );
                match mbarrier.adapter {
                    MbarrierExtendedAdapter::PointerTxCountBytesToTokenDroppingTxCount => {
                        output.push_str(
                            "/// `_arg0` must point to a live, initialized, eight-byte-aligned mbarrier in shared memory. `_arg2` must match the asynchronous transaction bytes.\n\
                             /// `_arg1` is retained for compatibility and is not a PTX operand.\n",
                        );
                    }
                    MbarrierExtendedAdapter::RawClusterAddressToVoid => output.push_str(
                        "/// `_arg0` must be a live remote shared-memory barrier address obtained through cluster address mapping.\n",
                    ),
                    MbarrierExtendedAdapter::PointerTokenToPredicate => output.push_str(
                        "/// `_arg0` must point to a live initialized barrier. `_arg1` must be a token for that barrier and phase.\n",
                    ),
                    MbarrierExtendedAdapter::PointerParityToPredicate => output.push_str(
                        "/// `_arg0` must point to a live initialized barrier. `_arg1` must be the expected phase parity.\n",
                    ),
                    MbarrierExtendedAdapter::ZeroOperandsToVoid => output.push_str(
                        "/// The call site must satisfy the scope and proxy-ordering contract named by the operation.\n",
                    ),
                    MbarrierExtendedAdapter::NanosecondsToVoid => output.push_str(
                        "/// `_arg0` is an approximate suspension duration; hardware may resume the thread earlier.\n",
                    ),
                }
            } else if let Some(copy) = &record.cp_async_copy {
                let bytes = copy.copy_size.bytes();
                writeln!(
                    output,
                    "/// `_arg0` must point to {bytes} writable bytes in shared memory and be aligned to {bytes} bytes."
                )
                .unwrap();
                if copy.source_size == CpAsyncSourceSize::Runtime {
                    writeln!(
                        output,
                        "/// `_arg2` must be at most {bytes}; `_arg1` must point to that many readable bytes in global memory and be aligned to {bytes} bytes."
                    )
                    .unwrap();
                } else {
                    writeln!(
                        output,
                        "/// `_arg1` must point to {bytes} readable bytes in global memory and be aligned to {bytes} bytes."
                    )
                    .unwrap();
                }
                output.push_str(
                    "/// Both ranges must remain valid, the source must remain unchanged, and the destination must not be accessed until this copy completes.\n\
                     /// The issuing thread must use a matching `cp.async` completion operation. Synchronize threads after completion before another thread accesses the destination.\n\
                     /// User-authored completion assembly must include a compiler memory clobber.\n",
                );
            } else if let Some(control) = &record.cp_async_control {
                if control.operation == CpAsyncControlOperation::WaitGroup {
                    output.push_str(
                        "/// `_arg0` must be a compile-time constant. Access only destinations whose copy groups this wait completes.\n",
                    );
                } else if control.operation == CpAsyncControlOperation::WaitAll {
                    output.push_str(
                        "/// This waits only for copies issued by the executing thread. Synchronize threads before another thread accesses a completed destination.\n",
                    );
                } else {
                    output.push_str(
                        "/// This commits only copies issued by the executing thread and does not wait for completion.\n",
                    );
                }
            } else if let Some(tcgen05) = &record.tcgen05 {
                if tcgen05_is_commit(tcgen05.operation) {
                    if tcgen05_is_multicast_commit(tcgen05.operation) {
                        output.push_str(
                            "/// `_arg0` must point to a live initialized cluster-shared mbarrier. `_arg1` must select valid CTA ranks in its cluster.\n",
                        );
                    } else {
                        output.push_str(
                            "/// `_arg0` must point to a live initialized mbarrier valid for this CTA-group mode.\n",
                        );
                    }
                    output.push_str(
                        "/// The same thread that issued the tracked asynchronous tcgen05 operations must issue this commit.\n",
                    );
                } else if tcgen05_is_shift(tcgen05.operation) {
                    output.push_str(
                        "/// `_arg0` must name a live tensor-memory allocation, and its lane component must be a multiple of 32.\n\
                         /// Completion must be tracked by a matching commit from that same thread and observed through the selected mbarrier before relying on shifted data.\n",
                    );
                } else if tcgen05.operation == Tcgen05Operation::Ld {
                    output.push_str(
                        "/// `_arg0` must name a live tensor-memory allocation covering the selected tile.\n\
                         /// All active warp lanes must execute convergently with the same address.\n\
                         /// Complete the matching tensor-memory load wait before consuming the returned registers.\n",
                    );
                    if tcgen05
                        .ld
                        .is_some_and(|ld| ld.shape == Tcgen05LdShape::M16x32bx2)
                    {
                        output.push_str(
                            "/// `_arg1` must be a compile-time constant; inline PTX encodes its low 32 bits.\n",
                        );
                    }
                } else if tcgen05.operation == Tcgen05Operation::St {
                    output.push_str(
                        "/// `_arg0` must name a live tensor-memory allocation covering the selected tile.\n\
                         /// All active warp lanes must execute convergently with the same address.\n\
                         /// Complete the matching tensor-memory store wait before relying on completion or reusing the affected storage.\n",
                    );
                    if tcgen05
                        .st
                        .is_some_and(|st| st.shape == Tcgen05LdShape::M16x32bx2)
                    {
                        output.push_str(
                            "/// `_arg1` must be a compile-time constant; inline PTX encodes its low 32 bits.\n",
                        );
                    }
                } else {
                    output.push_str(
                        "/// The caller must satisfy the tcgen05 address, lifetime, and participation rules.\n",
                    );
                }
            } else {
                output.push_str(
                    "/// `addr` must designate four writable bytes in global memory and be naturally aligned to four bytes.\n\
                     /// Do not overlap this operation with a whole-word atomic or any non-atomic access to either 16-bit lane.\n\
                     /// Racing atomics must use scopes that include each other; this relaxed GPU-scope operation is not atomic with host/system access.\n",
                );
            }
        }
        if record.rust.arguments.len() > 7 {
            output.push_str("#[allow(clippy::too_many_arguments)]\n");
        }
        if record.rust.must_use {
            output.push_str("#[must_use]\n");
        }
        output.push_str("#[inline(never)]\n");
        let safety = if record.rust.safe { "" } else { "unsafe " };
        let arguments = record
            .rust
            .arguments
            .iter()
            .enumerate()
            .map(|(index, ty)| format!("_arg{index}: {ty}"))
            .collect::<Vec<_>>()
            .join(", ");
        writeln!(
            output,
            "pub {safety}fn {}({arguments}) -> {} {{",
            record.rust.abi_id, record.rust.result,
        )
        .unwrap();
        writeln!(
            output,
            "    unreachable!(\"generated CUDA intrinsic `{}` executed outside device compilation\")",
            record.rust.canonical_path
        )
        .unwrap();
        output.push_str("}\n\n");
    }
    output
}

fn render_compat_register_mma(catalog: &CatalogFile, hash: &str) -> String {
    let mut output = rust_header(catalog, hash);
    output.push_str("// Included inside `cuda_device::wmma` to keep public paths stable.\n\n");
    for record in register_mmas(catalog).filter(|record| {
        record.register_mma.as_ref().is_some_and(|mma| {
            mma.compatibility_source == RegisterMmaCompatibilitySource::GeneratedStub
        })
    }) {
        let mma = record
            .register_mma
            .as_ref()
            .expect("register-MMA semantics");
        let [path] = record.rust.compatibility_paths.as_slice() else {
            panic!("generated register-MMA API requires one compatibility path");
        };
        assert_eq!(path, &format!("cuda_device::wmma::{}", record.rust.name));
        assert!(!record.rust.safe);
        assert!(record.rust.must_use);
        assert_eq!(record.rust.arguments.len(), 3);

        writeln!(output, "/// {}", record.summary).unwrap();
        writeln!(
            output,
            "/// Lowers to `{}`. C, A, and B are this lane's fragments in PTX register order.",
            expected_ptx_head(record)
        )
        .unwrap();
        writeln!(
            output,
            "/// Requires PTX {} and `{}`.",
            record.target.minimum_ptx,
            hardware_target_label(&record.target.hardware)
        )
        .unwrap();
        match mma.overflow {
            RegisterMmaOverflow::Wrapping => {
                output.push_str("/// Signed accumulator overflow wraps.\n");
            }
            RegisterMmaOverflow::Satfinite => {
                output.push_str(
                    "/// Signed accumulator overflow clamps to the finite `i32` range.\n",
                );
            }
            RegisterMmaOverflow::NotApplicable => {}
        }
        output.push_str("///\n/// # Safety\n");
        output.push_str(
            "/// All 32 lanes must execute the same instruction with the same qualifiers, and no lane may have exited.\n",
        );
        output.push_str(
            "/// `c`, `a`, and `b` must contain this lane's fragments in the documented PTX layout.\n",
        );
        writeln!(
            output,
            "/// See the [PTX MMA fragment layouts]({}).",
            record.target.ptx_isa_url
        )
        .unwrap();
        output.push_str("/// This register-only operation is not a memory fence.\n");
        output.push_str("#[must_use]\n#[inline(never)]\n");
        let arguments = ["c", "a", "b"]
            .into_iter()
            .zip(&record.rust.arguments)
            .map(|(name, ty)| format!("{name}: {ty}"))
            .collect::<Vec<_>>()
            .join(", ");
        writeln!(
            output,
            "pub unsafe fn {}({arguments}) -> {} {{",
            record.rust.name, record.rust.result
        )
        .unwrap();
        output.push_str("    let _ = (c, a, b);\n");
        writeln!(
            output,
            "    unreachable!(\"{} called outside CUDA kernel context\")",
            record.rust.name
        )
        .unwrap();
        output.push_str("}\n\n");
    }
    output
}

fn render_compat_sparse_mma(catalog: &CatalogFile, hash: &str) -> String {
    let mut output = rust_header(catalog, hash);
    output.push_str("// Included inside `cuda_device::wmma` to keep public paths stable.\n\n");
    for record in sparse_mmas(catalog).filter(|record| {
        record.sparse_mma.as_ref().is_some_and(|mma| {
            mma.compatibility_source == SparseMmaCompatibilitySource::GeneratedStub
        })
    }) {
        let mma = record.sparse_mma.as_ref().expect("sparse-MMA semantics");
        let [path] = record.rust.compatibility_paths.as_slice() else {
            panic!("generated sparse-MMA API requires one compatibility path");
        };
        assert_eq!(path, &format!("cuda_device::wmma::{}", record.rust.name));
        assert!(matches!(
            mma.adapter,
            SparseMmaAdapter::C2U32A4U32B4U32MetadataU32SelectorU32ToD2U32
                | SparseMmaAdapter::C4F32A4U32B4U32MetadataU32SelectorU32ToD4F32
                | SparseMmaAdapter::C4I32A2U32B2U32MetadataU32SelectorU32ToD4I32
                | SparseMmaAdapter::C4I32A4U32B4U32MetadataU32SelectorU32ToD4I32
        ));

        writeln!(output, "/// {}", record.summary).unwrap();
        writeln!(
            output,
            "/// Lowers to `{}`. C, A, B, and metadata are this lane's PTX fragments.",
            sparse_mma_ptx_head(record)
        )
        .unwrap();
        writeln!(
            output,
            "/// Requires PTX {} and `{}`.",
            record.target.minimum_ptx,
            hardware_target_label(&record.target.hardware)
        )
        .unwrap();
        match mma.overflow {
            SparseMmaOverflow::NotApplicable => {}
            SparseMmaOverflow::Wrapping => {
                output.push_str("/// Signed accumulator overflow wraps.\n");
            }
            SparseMmaOverflow::Satfinite => output
                .push_str("/// Signed accumulator overflow clamps to the finite `i32` range.\n"),
        }
        output.push_str("///\n/// # Safety\n");
        output.push_str(
            "/// All 32 lanes must execute the same instruction with the same qualifiers, and no lane may have exited.\n",
        );
        let (c_count, a_count, b_count, _) = sparse_mma_fragment_counts(record);
        writeln!(
            output,
            "/// `c`, `a`, and `b` must contain this lane's {c_count}-, {a_count}-, and {b_count}-register fragments; `metadata` must contain its sparse metadata."
        )
        .unwrap();
        writeln!(output, "/// {}", sparse_mma_metadata_rule(mma)).unwrap();
        writeln!(
            output,
            "/// `selector` must be {}.",
            sparse_mma_selector_description(record)
        )
        .unwrap();
        writeln!(
            output,
            "/// See the [PTX sparse MMA fragment layouts]({}).",
            record.target.ptx_isa_url
        )
        .unwrap();
        output.push_str("/// This register-only operation is not a memory fence.\n");
        output.push_str("#[must_use]\n#[inline(never)]\n");
        let arguments = ["c", "a", "b", "metadata", "selector"]
            .into_iter()
            .zip(&record.rust.arguments)
            .map(|(name, ty)| format!("{name}: {ty}"))
            .collect::<Vec<_>>()
            .join(", ");
        writeln!(
            output,
            "pub unsafe fn {}({arguments}) -> {} {{",
            record.rust.name, record.rust.result
        )
        .unwrap();
        output.push_str("    let _ = (c, a, b, metadata, selector);\n");
        writeln!(
            output,
            "    unreachable!(\"{} called outside CUDA kernel context\")",
            record.rust.name
        )
        .unwrap();
        output.push_str("}\n\n");
    }
    output
}

fn render_compat_sreg(catalog: &CatalogFile, hash: &str) -> String {
    let mut output = rust_header(catalog, hash);
    output.push_str(
        "// This file is included lexically inside `cuda_device::thread` so existing\n// DefPaths remain stable during the generated-intrinsics migration.\n\n",
    );
    for record in sregs(catalog) {
        let Some(path) = record
            .rust
            .compatibility_paths
            .iter()
            .find(|path| path.starts_with("cuda_device::thread::"))
        else {
            continue;
        };
        let name = path.rsplit("::").next().unwrap();
        writeln!(
            output,
            "/// Compatibility spelling for `{}`.",
            record.rust.public_path
        )
        .unwrap();
        writeln!(
            output,
            "/// The compiler replaces this call with {}.",
            source_label(record)
        )
        .unwrap();
        output.push_str("#[allow(non_snake_case)]\n#[inline(never)]\n");
        let safety = if record.rust.safe { "" } else { "unsafe " };
        writeln!(
            output,
            "pub {safety}fn {name}() -> {} {{",
            record.rust.result
        )
        .unwrap();
        writeln!(
            output,
            "    unreachable!(\"generated CUDA intrinsic `{path}` executed outside device compilation\")"
        )
        .unwrap();
        output.push_str("}\n\n");
    }
    output
}

fn render_compat_cluster_sreg(catalog: &CatalogFile, hash: &str) -> String {
    let mut output = rust_header(catalog, hash);
    output.push_str(
        "// This file is included inside `cuda_device::cluster`.\n// Its private leaves let public helpers compose generated reads.\n\n",
    );
    for record in sregs(catalog) {
        let Some(path) = record
            .rust
            .compatibility_paths
            .iter()
            .find(|path| path.starts_with("cuda_device::cluster::__"))
        else {
            continue;
        };
        let name = path.rsplit("::").next().unwrap();
        writeln!(
            output,
            "/// Private compatibility spelling for `{}`.",
            record.rust.public_path
        )
        .unwrap();
        writeln!(
            output,
            "/// The compiler replaces this call with `{}`.",
            llvm(record).symbol
        )
        .unwrap();
        output.push_str("#[allow(non_snake_case)]\n#[inline(never)]\n");
        writeln!(
            output,
            "pub(crate) fn {name}() -> {} {{",
            record.rust.result
        )
        .unwrap();
        writeln!(
            output,
            "    unreachable!(\"generated CUDA intrinsic `{path}` executed outside device compilation\")"
        )
        .unwrap();
        output.push_str("}\n\n");
    }
    output
}

fn render_compat_special_register_module(
    catalog: &CatalogFile,
    hash: &str,
    module: &str,
) -> String {
    let mut output = rust_header(catalog, hash);
    writeln!(
        output,
        "// Included inside `cuda_device::{module}` to keep existing paths stable.\n"
    )
    .unwrap();
    let prefix = format!("cuda_device::{module}::");
    for record in sregs(catalog).filter(|record| record.special_register.is_some()) {
        let Some(path) = record
            .rust
            .compatibility_paths
            .iter()
            .find(|path| path.starts_with(&prefix))
        else {
            continue;
        };
        let name = path.rsplit("::").next().unwrap();
        writeln!(output, "/// {}", record.summary).unwrap();
        writeln!(output, "/// Generated from {}.", source_label(record)).unwrap();
        output.push_str("#[inline(never)]\n");
        let safety = if record.rust.safe { "" } else { "unsafe " };
        writeln!(
            output,
            "pub {safety}fn {name}() -> {} {{",
            record.rust.result
        )
        .unwrap();
        writeln!(
            output,
            "    unreachable!(\"generated CUDA intrinsic `{path}` executed outside device compilation\")"
        )
        .unwrap();
        output.push_str("}\n\n");
    }
    output
}

fn render_compat_fence(catalog: &CatalogFile, hash: &str) -> String {
    let mut output = rust_header(catalog, hash);
    output.push_str(
        "// This file is included inside `cuda_device::fence` so existing paths stay stable.\n\n",
    );
    for record in sync_intrinsics(catalog).filter(|record| threadfence_ptx_level(record).is_some())
    {
        let Some(path) = record
            .rust
            .compatibility_paths
            .iter()
            .find(|path| path.starts_with("cuda_device::fence::"))
        else {
            continue;
        };
        let name = path.rsplit("::").next().unwrap();
        writeln!(output, "/// {}", record.summary).unwrap();
        writeln!(
            output,
            "/// The compiler replaces this call with `{}`.",
            llvm(record).symbol
        )
        .unwrap();
        output.push_str("#[inline(never)]\n");
        writeln!(output, "pub fn {name}() {{").unwrap();
        writeln!(
            output,
            "    unreachable!(\"generated CUDA intrinsic `{path}` executed outside device compilation\")"
        )
        .unwrap();
        output.push_str("}\n\n");
    }
    output
}

fn render_compat_dotprod(catalog: &CatalogFile, hash: &str) -> String {
    let mut output = rust_header(catalog, hash);
    output.push_str("// Included inside `cuda_device::dotprod` to keep existing paths stable.\n\n");
    for record in dot_products(catalog) {
        let path = record
            .rust
            .compatibility_paths
            .iter()
            .find(|path| path.starts_with("cuda_device::dotprod::"))
            .expect("dot-product compatibility path");
        let arguments = record
            .rust
            .arguments
            .iter()
            .enumerate()
            .map(|(index, ty)| format!("arg{index}: {ty}"))
            .collect::<Vec<_>>()
            .join(", ");
        let values = (0..record.rust.arguments.len())
            .map(|index| format!("arg{index}"))
            .collect::<Vec<_>>()
            .join(", ");
        writeln!(output, "/// {}", record.summary).unwrap();
        output.push_str("#[inline(never)]\n");
        writeln!(
            output,
            "pub fn {}({arguments}) -> {} {{",
            record.rust.name, record.rust.result
        )
        .unwrap();
        if record.rust.arguments.len() == 1 {
            writeln!(output, "    let _ = {values};").unwrap();
        } else {
            writeln!(output, "    let _ = ({values});").unwrap();
        }
        writeln!(
            output,
            "    unreachable!(\"generated CUDA intrinsic `{path}` executed outside device compilation\")"
        )
        .unwrap();
        output.push_str("}\n\n");
    }
    output
}

